@startuml
!theme plain

class "HouseBuilder" as HouseBuilder {
  <<interface>>
  +buildBasic()
  +buildBody()
  +buildRoof()
  +finish()
}

class "CommonHouseBuilder" as CommonHouseBuilder {
  -House house
  +buildBasic()
  +buildBody()
  +buildRoof()
  +finish()
}

class "LuxuryHouseBuilder" as LuxuryHouseBuilder {
  -House house
  +buildBasic()
  +buildBody()
  +buildRoof()
  +finish()
}

class "House" as House {
  -String type
  -boolean base
  -boolean body
  -boolean roof
}

class "Decorate" as Decorate {
  -HouseBuilder houseBuilder
  +construct()
}

class "Client" as Client {
}

HouseBuilder <|-- CommonHouseBuilder
HouseBuilder <|-- LuxuryHouseBuilder
CommonHouseBuilder o-- House
LuxuryHouseBuilder o-- House
Decorate --> HouseBuilder
Client --> Decorate

note right of House : 具体产品类
note left of Decorate : 具体建造对象

@enduml
